"""
MKT Context Commentary — Genesis chapters 10–12
Run: python3 scripts/zc-context-genesis-10-12.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (ch12:v1 already present; merge_comm skips it)

Key decisions in this range:
- Ch10 Table of Nations: treated as a genuine ethnographic document with ANE historical
  correlates; specific peoples identified where attestable (Gomer=Cimmerians, Javan=Greeks,
  Madai=Medes, etc.)
- Ch10:v4 Rodanites: some MSS read Dodanites (=Dodanim/Rhodes); MKT follows MT Rodanites
- Ch10:v9 Nimrod "before the LORD": treated as ambiguous (superlative or defiant)
- Ch11:v4 "tower reaching to the heavens": ziggurat interpretation noted with Etemenanki evidence
- Ch11:v9 Babel etymology: Hebrew bālal (confuse) vs. Babylonian Bāb-il (gate of god) noted
- Ch12:v3 "all peoples on earth will be blessed through you": Paul's Gal 3:8 citation noted
- Ch12:10-20 Egypt episode: pattern-parallel to Exodus noted (famine, plagues, expulsion
  with wealth) without reducing the episode to mere prefiguration
- Abram's "sister" deception treated honestly; ANE marriage-law background given
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_CONTEXT = {
  "10": {
    "1": """<p>The <em>tôlĕḏôt</em> formula — "This is the account of Shem, Ham and Japheth" — opens the Table of Nations, the most comprehensive ancient ethnographic document from the ANE. No other ancient text attempts to trace all known peoples to a single family origin with the systematic comprehensiveness of Gen 10. The Table lists 70 peoples (a number that likely represents the totality of known nations — cf. the 70 elders of Israel in Exod 24:1; the 70 nations in rabbinic tradition). The phrase "who themselves had sons after the flood" anchors the Table in the post-flood covenant context: every people listed is a beneficiary of the Noahic covenant (9:10-16).</p>""",
    "2": """<p>The sons of Japheth are predominantly the Indo-European peoples of the north and west: Gomer (the Cimmerians, known in Assyrian records as <em>Gimirrai</em>; Ezek 38:6), Magog (applied in Ezek 38-39 to a northern enemy power; traditionally identified with Scythians), Madai (the Medes — major ANE power that co-conquered Babylon with Cyrus in 539 BCE), Javan (the Ionians/Greeks — <em>Iavan</em> is the Hebrew form of Iōnia; Dan 8:21), Tubal (the Tabali of Asia Minor; Ezek 27:13), Meshek (the Mushki of Asia Minor, also in Ezek 27:13; 38:2), Tiras (uncertain — possibly Etruscans or Thracians). The Japhethic line encompasses the peoples of Asia Minor, the Aegean, the Iranian plateau, and the northern steppes.</p>""",
    "3": """<p>Sons of Gomer: Ashkenaz (the <em>Ashkuz</em> of Assyrian records — a Scythian people from the Black Sea region; Jer 51:27; in later Jewish usage, Ashkenaz refers to Germany, hence Ashkenazi Jews), Riphath (uncertain location — possibly the Riphaean mountains of ancient geography), Togarmah (<em>Til-Garimmu</em> in Assyrian sources — a kingdom in eastern Asia Minor; Ezek 27:14 mentions Togarmah trading horses and mules with Tyre; Ezek 38:6 places it in "the far north").</p>""",
    "4": """<p>Sons of Javan (Greeks): Elishah (possibly Cyprus — the island of Alashiya was known to the Hittites as a copper source; Ezek 27:7), Tarshish (a distant western trading partner associated with silver, tin, and iron — Tartessos in Spain or Sardinia are the most plausible identifications; Jon 1:3's Tarshish represents the far end of the known world), Kittites (Kition on Cyprus — later applied broadly to Greeks and then Romans in Daniel 11:30), Rodanites (Rhodes — some manuscripts read Dodanites/Dodanim; the MKT follows the MT Rodanites). The sons of Javan represent the Greek-speaking maritime world of the eastern Mediterranean.</p>""",
    "5": """<p>"From these the maritime peoples spread out into their territories by their clans within their nations, each with its own language" — the closing formula introduces a narrative complexity: ch10 describes peoples with distinct languages, yet ch11 begins with "the whole world had one language." The relationship between these chapters is not strictly chronological: ch10 presents the result (diverse nations), ch11 explains the mechanism (Babel causing the diversity), and ch12 narrows to the covenant-line (Abram). The literary order is thematic — global scope (ch10) → the mechanism of dispersal (ch11) → the covenant response to human rebellion (ch12).</p>""",
    "6": """<p>The sons of Ham are the northeastern African and southwestern Asian peoples: Cush (the region of Nubia/Ethiopia/Sudan — south of Egypt along the Nile; a major civilization and trading partner of Egypt), Egypt (<em>Miṣrayim</em>, the standard Hebrew name for Egypt — the dual form may indicate Upper and Lower Egypt), Put (Libya or broader North Africa — Nah 3:9; Ezek 27:10), Canaan (the Canaanite peoples of the promised land, whose land was cursed in 9:25). The Hamitic genealogy establishes the ethnic relationships between Africa, the Arabian peninsula, and the Canaanite cities that Israel will encounter.</p>""",
    "7": """<p>Sons of Cush: Seba (possibly a Nubian people — Ps 72:10 names Seba alongside Sheba), Havilah (possibly in Arabia — cf. Gen 2:11 where Havilah is associated with gold), Sabtah, Raamah, Sabteka (all likely Arabian trading peoples). Sons of Raamah: Sheba (the Sabaean kingdom of southern Arabia/Ethiopia — the Queen of Sheba who visited Solomon came from this wealthy trade empire, 1 Kgs 10:1-13; Ps 72:10) and Dedan (an oasis trading center in northwest Arabia — a hub on the incense route; Jer 25:23; Ezek 27:15,20). The clustering of these Arabian trading peoples in the Cushite line reflects their historical role as intermediaries between Africa and the Fertile Crescent.</p>""",
    "8": """<p>Nimrod is the Table's most narratively developed figure — the only person whose character is described rather than merely listed. "Cush was the father of Nimrod, who became a mighty warrior (<em>gibbôr</em>) on the earth" — the word <em>gibbôr</em> connects Nimrod to the pre-flood heroic culture (Gen 6:4: the Nephilim are called <em>gibbôrîm</em>). Nimrod is the post-flood embodiment of the pre-flood hero tradition: a mighty man who built the first empire. The name Nimrod has been connected with Naram-Sin (the Akkadian king who deified himself) and with the epic hero Gilgamesh (who is also a great hunter and city-builder in the Gilgamesh epic). Whether these are direct identifications or typological parallels, Nimrod represents the Hamite imperial ambition that will manifest at Babel.</p>""",
    "9": """<p>"A mighty hunter (<em>gibbôr ṣayid</em>) before the LORD (<em>lipnê YHWH</em>)" — the phrase <em>lipnê YHWH</em> (before/in the face of the LORD) is ambiguous: it may function as a superlative ("the greatest hunter in YHWH's assessment") or may carry the nuance of defiant boldness in YHWH's presence — hunting <em>before/against</em> YHWH as a rival. The same phrase is used in positive contexts (Noah walked before God, 6:9) and neutral superlative contexts (Num 3:4), so the ambiguity is genuine. The proverb "like Nimrod, a mighty hunter before the LORD" was current in Israelite tradition — Nimrod was already a legendary figure when Genesis was written, just as Gilgamesh was legendary in Mesopotamia. The naming of a proverb about him implies widespread cultural recognition.</p>""",
    "10": """<p>"The first centers of his kingdom were Babylon, Uruk, Akkad and Kalneh, in Shinar" — these are historically attested Mesopotamian cities: Babylon (the great city of Babylonia — later Nebuchadnezzar's capital; the city that will conquer Jerusalem in 587 BCE), Uruk (ancient Erech — one of the oldest cities in the world, ca. 4000 BCE; home of the historical Gilgamesh tradition), Akkad (capital of the Akkadian Empire under Sargon the Great, ca. 2334-2279 BCE — the first truly imperial state in the ANE), Kalneh (uncertain — possibly Nippur or another Babylonian city). "Shinar" is the biblical name for the Babylonian plain — the same word used in 11:2 for the Babel location. Nimrod is credited with founding the first historical empire: the Mesopotamian city-state system.</p>""",
    "11": """<p>"From that land he went to Assyria, where he built Nineveh, Rehoboth Ir, Calah" — the Assyrian cities are equally historical: Nineveh (capital of the Neo-Assyrian Empire at its height; Jonah's destination; destroyed in 612 BCE by the Babylonians and Medes), Calah (Kalhu/Nimrud in modern Iraq — the administrative capital of the Assyrian Empire under Ashurnasirpal II and Shalmaneser III; excavated in the 19th century revealing extensive palace complexes and Assyrian ivories). Rehoboth Ir (literally "city plazas/wide streets") is uncertain — possibly a district name rather than a separate city. Nimrod as founder of both Babylon and Nineveh establishes him as the progenitor of the two great empires that dominated Israel's history (Assyria destroyed northern Israel in 722 BCE; Babylon destroyed Jerusalem in 587 BCE).</p>""",
    "12": """<p>"Resen, which is between Nineveh and Calah — which is the great city" — Resen's location between Nineveh and Calah (approximately 30 kilometers apart in the Tigris River valley) has not been definitively identified archaeologically. "Which is the great city" may refer to Resen, Nineveh, or Calah — the reference is ambiguous. The Assyrian capital region (including Nineveh, Calah, Khorsabad, and Assur) formed a metropolitan complex sometimes called the "Assyrian triangle." The narrative's attention to the great cities of the Nimrodic empire is a theological geography: these will be the adversaries of YHWH's covenant people throughout the biblical narrative.</p>""",
    "13": """<p>"Egypt was the father of the Ludites, Anamites, Lehabites, Naphtuhites" — these are Egyptian-derived peoples, most of whose exact identifications are uncertain: Ludites (possibly the Lydians of western Asia Minor, though this conflicts with the Shemite identification of Lud in v22), Anamites (unknown), Lehabites (possibly related to Libya — <em>Lubim</em>), Naphtuhites (possibly the people of northern Egypt — <em>Npt</em> in Egyptian texts). The Egyptian genealogy establishes the broad cultural sphere of Egyptian influence in northeastern Africa and the eastern Mediterranean coast.</p>""",
    "14": """<p>"Pathrusites, Kasluhites (from whom the Philistines came) and Caphtorites" — Pathrusites are the people of Pathros (Upper Egypt — the Nile valley south of Memphis; Isa 11:11; Jer 44:1). Kasluhites and Caphtorites are both associated with the Philistines — Amos 9:7 identifies the Philistines as coming from Caphtor (Crete or the Aegean islands), consistent with the archaeological evidence that the Philistines were part of the "Sea Peoples" migration from the Aegean world ca. 1200 BCE. The Philistines' placement in the Hamitic genealogy through Egypt establishes the theological context for the later Philistine-Israel conflict: the Philistines are descended from Ham, whose line includes those under the curse of Canaan (9:25).</p>""",
    "15": """<p>"Canaan was the father of Sidon his firstborn, and of the Hittites" — Sidon (the great Phoenician city on the Lebanese coast — a major Mediterranean trading power; the firstborn of Canaan indicates its prominence) and the Hittites (the Neo-Hittite city-states of Syria-Palestine, who were the remnants of the great Hittite Empire of Anatolia — 1600-1178 BCE). The inclusion of the Hittites in the Canaanite line explains the biblical usage of "Hittites" as Canaanite peoples (cf. Gen 23:3-20: Abraham buying the cave of Machpelah from the "Hittites" who lived in Hebron, who are local Canaanites, not the imperial Hittites of Anatolia). The genealogy is the Table of Nations' explanation for who the Israelites will encounter when they enter the promised land.</p>""",
    "16": """<p>Jebusites (the pre-Israelite inhabitants of Jerusalem — the city David captures in 2 Sam 5:6-8 and renames the City of David; Araunah the Jebusite's threshing floor becomes the temple mount in 2 Sam 24:18-25), Amorites (a broad term covering various Syro-Canaanite peoples — Hammurabi of Babylon was Amorite; the five Amorite kings of Josh 10:5 are southern Canaanite rulers; in Amos 2:9-10 the Amorites represent the entire pre-Israelite population of Canaan), Girgashites (a Canaanite people listed in the conquest accounts — Deut 7:1; Josh 3:10 — but otherwise unknown in extra-biblical sources).</p>""",
    "17": """<p>Hivites (associated with Shechem in Gen 34 and Gibeon in Josh 9; a Canaanite people whose exact identity is uncertain — some MSS and the LXX confuse Hivites with Horites/Hurrians), Arkites (inhabitants of Arka on the Lebanese coast — a city known from Egyptian texts), Sinites (uncertain — possibly on the Lebanese coast). These less prominent Canaanite groups are included in the Table's comprehensive scope: the promise of the land to Abraham's descendants encompasses the full range of its current inhabitants, not just the major powers.</p>""",
    "18": """<p>Arvadites (Arvad/Aradus — an island city off the Syrian coast; a significant Phoenician trading center; Ezek 27:8,11), Zemarites (Sumur/Simyra — a Syrian coastal city known from the Amarna letters), Hamathites (Hamath — a major city on the Orontes River in Syria, the northernmost boundary of the Davidic kingdom, 2 Sam 8:9; 1 Kgs 8:65). "Later the Canaanite clans scattered" — the dispersion of the Canaanite peoples into their territories is the post-flood fulfillment of the Table's geographic claims: these peoples are where they are because of the genealogical relationships traced here.</p>""",
    "19": """<p>"The borders of Canaan reached from Sidon toward Gerar as far as Gaza, and then toward Sodom, Gomorrah, Admah and Zeboyim, as far as Lasha" — the territorial definition of Canaan maps the precise region that YHWH will give to Abraham's descendants. Sidon (north) to Gaza (southwest coast) to Sodom/Gomorrah (south, in the Dead Sea region) defines the territory. The inclusion of Sodom and Gomorrah in Canaan's territorial borders is deliberate: the cities that will be destroyed in ch19 are within the promised land. The Table of Nations thus maps not only the ethnic geography of the ANE but the specific territory of the Abrahamic covenant promise.</p>""",
    "20": """<p>The closing formula for Ham's genealogy — "by their clans (<em>lĕmišpĕḥōtām</em>) and languages (<em>liĕšōnōtām</em>), in their territories (<em>bĕʾarṣōtām</em>) and nations (<em>bĕgôyēhem</em>)" — uses four categories that structure the Table of Nations as a whole. The fourfold taxonomy (clan + language + territory + nation) describes human social organization in its full complexity: the Table is not merely a genealogy but an ethnography, mapping the intersection of kinship, language, geography, and political identity. This is the most developed sociological taxonomy in any ancient Near Eastern text before the Assyrian annals.</p>""",
    "21": """<p>"Shem was the ancestor of all the sons of Eber (<em>bĕnê ʿēḇer</em>)" — the designation of Shem as the ancestor of the sons of Eber is the Table's most significant theological marker: <em>ʿēḇer</em> (Eber) is the eponymous ancestor of the Hebrews (<em>ʿiḇrî</em> — Hebrew). The term "Hebrew" derives from this genealogical line. The Table of Nations identifies the covenant-seed line within the universal human family: out of all 70 nations, one line within Shem's genealogy (Shem → Arphaxad → Shelah → Eber → Peleg → Reu → Serug → Nahor → Terah → Abram) carries the covenant promise forward. The Table contextualizes this narrowing: the covenant with Abram is not tribal favoritism but the selection of one thread from the full tapestry of human diversity.</p>""",
    "22": """<p>The sons of Shem: Elam (the Elamite kingdom east of Mesopotamia — a major ANE power; Elam captures Lot in Gen 14:1-12; Isa 11:11 includes Elamites in the diaspora), Asshur (Assyria — note the complexity: Asshur appears here as a Shemite, yet in vv11-12 Nimrod the Hamite builds Nineveh; the table reflects the layered ethnic history of Assyria as both Semitic in language and mixed in population), Arphaxad (the key line to Abram — traced in ch11's genealogy), Lud (possibly the Lydians of western Asia Minor, though this conflicts with Ludites being Hamitic in v13 — the identification is debated), Aram (the Aramean people of Syria — Israel's close relatives, with whom they share significant cultural and linguistic affinity; Aramaic became the diplomatic language of the ANE and later the common language of Palestine in Jesus's day).</p>""",
    "23": """<p>Sons of Aram: Uz (the land where Job lived — Job 1:1 — placing Job within the Aramean/Shemite cultural sphere; Jer 25:20 lists Uz alongside the Philistines and Edom), Hul (uncertain — possibly a region east of the Jordan), Gether (uncertain), Meshek (in the MT — possibly distinct from the Japhethite Meshek of v2, though some read Mash/Massa here; the LXX reads Mash). The sons of Aram establish the ethnic geography of Syria and the Transjordanian regions — peoples with whom Israel had both kinship ties (Jacob's mother Rebekah was from Aram, Gen 25:20) and conflict.</p>""",
    "24": """<p>Arphaxad → Shelah → Eber — the three-generation descent to Eber (the eponymous ancestor of the Hebrews) traces the covenant-line within the Shemite genealogy. The progression narrows rapidly: from all of Shem's descendants (five sons, v22) to one son (Arphaxad) to one grandson (Shelah) to one great-grandson (Eber) who will give his name to the people of God. The genealogy demonstrates the principle of selective narrowing that governs the entire biblical narrative: from all humanity (ch10) to one man (ch12), the covenant line is progressively specified.</p>""",
    "25": """<p>"Two sons were born to Eber: One was named Peleg, because in his time the earth was divided (<em>nipleḡāh</em>)" — the name Peleg (<em>pālag</em> = to divide/split) is explained by the division of the earth. The natural referent for "division of the earth" is the Babel dispersion (ch11) — the Hebrew wordplay (<em>Peleg / niplĕgāh</em>) connects the genealogical name to the historical event. The notation "in his time" anchors the Babel event chronologically within the Shemite genealogy. The divided earth of Peleg's time is the world that Abram will be called out of in ch12 — the world of many languages and many nations, into which the covenant blessing will flow (12:3).</p>""",
    "26": """<p>Joktan's line (vv26-29) represents the tribes of the Arabian peninsula — 13 sons covering the geography of ancient Arabia from Yemen to the Persian Gulf. Almodad (unknown), Sheleph (unknown), Hazarmaveth (<em>Haḑramawt</em> — the well-known region of southern Arabia in modern Yemen; one of the most distinctive geographical identifications in the Table, verifiable from ancient South Arabian inscriptions), Jerah (possibly a lunar-calendar people — <em>yāreḥ</em> = moon). The Arabian genealogy establishes the ethnic background of the peoples living in the territories between Israel and Egypt — significant for the later caravans (Ishmaelites, Midianites, Sabeans) that appear in the Joseph and Job narratives.</p>""",
    "27": """<p>Hadoram, Uzal (<em>Ṣanʿāʾ</em>, the capital of modern Yemen — medieval Arabic sources identify Uzal with Sana'a, the ancient capital of Arabia Felix), Diklah (possibly the palm-tree region of Arabia — <em>dĕqel</em> = palm tree in Aramaic). These Arabian tribal ancestors establish the genealogical context for the "sons of the East" (<em>bĕnê qedem</em>) who appear throughout the OT — the semi-nomadic trading peoples of the Syrian-Arabian desert whose caravans connected Egypt with Mesopotamia.</p>""",
    "28": """<p>Obal (unknown location), Abimael (unknown — the <em>ab-il</em> element suggests a theophoric name meaning "God is my father," unusual in an ethnic genealogy), Sheba (the Sabaean kingdom — appearing here in the Joktanite line and also in v7 in the Cushite line, reflecting the mixed ethnic heritage of the ancient South Arabian kingdoms; the Queen of Sheba who visits Solomon represents this wealthy spice-and-gold trading civilization, 1 Kgs 10:1-13).</p>""",
    "29": """<p>Ophir (the famous gold-producing region associated with Solomon's naval expeditions — 1 Kgs 9:28; 10:11; Job 22:24; Ps 45:9; the location of Ophir is debated: India, Arabia, and eastern Africa have all been proposed), Havilah (appearing also in v7 in the Cushite line — indicating the overlapping territorial and ethnic claims of Arabian geography), Jobab (possibly connected with Job's name — <em>ʾiyyôḇ</em> — placing the patriarch Job within the Joktanite Arabian sphere consistent with Job 1:1's identification of Uz as his homeland). The 13 sons of Joktan (unusual — other genealogies rarely list 13 descendants of one person) cover an unusually specific geographic area, suggesting the Table preserves specific ethnographic knowledge about southern Arabian tribes.</p>""",
    "30": """<p>"The region where they lived stretched from Mesha toward Sephar, in the eastern hill country" — Mesha and Sephar are uncertain — possibly Massa in the Arabian peninsula (Gen 25:14; 1 Chr 1:30) and Ẓafar in Yemen respectively. The "eastern hill country" (<em>har haqqedem</em>) is the highland region of Arabia. The geographic scope of the Joktanite territory (from northwest Arabia to Yemen) represents one of the most specific and geographically precise claims in the Table of Nations — the Arabian interior that was a major ancient trading zone.</p>""",
    "31": """<p>The closing formula for Shem's genealogy mirrors the formula for Ham (v20) and anticipates the master closing formula of v32. The fourfold taxonomy (clans, languages, territories, nations) is applied consistently to each of Noah's three sons, giving the Table a formal symmetry that signals its character as a structured literary and ethnographic document, not merely a genealogical list. The consistent formula also emphasizes that the diversity of human cultures — languages, territories, nations — is a divinely ordered reality, not a defect requiring correction (until the disorder of Babel, ch11).</p>""",
    "32": """<p>The master closing formula — "these are the clans of Noah's sons, according to their lines of descent, within their nations. From these the nations spread out over the earth after the flood" — closes the Table with the universal scope statement that opened it (v1). Every people, every language, every territory ultimately traces to one surviving family. The Table of Nations is the biblical basis for the unity of humanity: the diversity of ch10 is the diversity of one family. This universal human kinship is the foundation for the Abrahamic covenant's universal scope (12:3: "all peoples on earth will be blessed through you") — the covenant blesses the family traced in this Table.</p>"""
  },
  "11": {
    "1": """<p>"The whole world had one language and a common speech (<em>deḇārîm ʾăḥādîm</em>)" — the phrase "one set of words/speech" may mean a shared vocabulary and idiom, not merely a single language. Linguistic unity enables the cooperative project that follows. In ANE thought, language was a divine gift: the Sumerian composition "Enmerkar and the Lord of Aratta" describes a primordial golden age when all peoples "praised Enlil with one tongue" — a memory of primordial linguistic unity before the gods multiplied languages. Genesis shares the cultural memory of an original unified speech while giving it a different narrative resolution: at Babel, YHWH multiplies language as judgment, not a natural development.</p>""",
    "2": """<p>"As people moved eastward (<em>miqqedem</em>)" — the Hebrew <em>miqqedem</em> can mean "from the east" or "eastward." In Genesis, eastward movement consistently signals movement away from the divine presence: the cherubim guard the east side of Eden (3:24); Cain moves east of Eden to Nod (4:16); and now "people moved eastward" toward the plain of Shinar. The eastward direction is the theological compass of Genesis's geography — the further east from Eden's garden, the further from covenant relationship with YHWH. Settling in Shinar (Babylonia) rather than moving toward Canaan (the promised land to the west) is itself a directional choice laden with theological implication.</p>""",
    "3": """<p>"They used brick instead of stone, and tar (<em>ḥēmār</em>) for mortar" — the narrative's construction detail is culturally and geographically specific. Stone construction was the characteristic building material of the hill country of Canaan and the Levant (where the Israelite audience lived). Kiln-fired brick and bitumen (asphalt) mortar were the characteristic materials of Mesopotamia, where stone was scarce but river clay was abundant. Archaeological evidence from the great ziggurats of Mesopotamia — particularly the ziggurat of Ur (Ur-Nammu, ca. 2100 BCE) and the ziggurat of Babylon (Etemenanki) — confirms they were built of fired brick with bitumen mortar, exactly as described. The narrative is encoding a geographical and cultural signature: this is Babylonian construction, identifiable to any reader familiar with the Mesopotamian building tradition.</p>""",
    "4": """<p>"Let us build ourselves a city, with a tower that reaches to the heavens (<em>wĕrōʾšô ḇaššāmayim</em>), so that we may make a name (<em>šēm</em>) for ourselves; otherwise we will be scattered" — three motivations: urban settlement, vertical reach toward heaven, and name-making. The <em>šēm</em> (name) they seek to make echoes the name of Noah's son Shem (<em>Šēm</em>) and anticipates YHWH's promise to make Abram's name great (12:2: <em>wĕʾăgadĕlāh šĕmekā</em>). At Babel, humans seek to manufacture their own greatness; in the covenant, YHWH grants name-greatness as a gift. The tower "reaching to the heavens" reflects the Mesopotamian ziggurat theology: ziggurats were mountain-temples designed to connect heaven and earth, the place where the deity descended to meet humans. The Babylonian name for the Babylon ziggurat — Etemenanki ("house of the foundation of heaven and earth") — captures the same cosmological ambition. The fear of being scattered (which the builders try to prevent) is precisely what YHWH enacts (v8) — the ironic reversal is built into the narrative's structure.</p>""",
    "5": """<p>"The LORD came down to see the city and the tower the people were building" — the divine descent is simultaneously theophanic and ironic. The builders aimed their tower to "reach heaven"; YHWH must descend to observe what they built. The vast gap between the builders' ambition and the actual scale of their achievement is the narrative's pointed theological comment: what humans imagine as reaching to God requires God to bend down to see it. The same ironic divine descent appears in Gen 18:21 (Sodom: "I will go down and see if what they have done is as bad as the outcry suggests"). The anthropomorphism is deliberate — YHWH accommodates himself to human observation while simultaneously demonstrating the absurdity of human pretension to heaven-reaching.</p>""",
    "6": """<p>"Nothing they plan to do will be impossible for them" — the divine assessment of unified humanity's cooperative potential is remarkable. YHWH does not dismiss the builders as incapable; he acknowledges the power of linguistic unity and shared purpose directed toward collective ambition. The concern is not that they will literally reach heaven but that fallen humanity operating in coordinated unity and directed toward self-exaltation has no natural limit. The same communicative unity that could advance human flourishing is being directed toward the Babel program — building a civilization centered on human name-making rather than covenant relationship with YHWH. The divine intervention is not fear of human power but the judgment of a directional orientation.</p>""",
    "7": """<p>"Come, let us go down and confuse (<em>nāḇĕlāh</em>) their language" — the divine plural (cf. 1:26: "let us make mankind") indicates the divine council's deliberative action. The verb <em>bālal</em> (to confuse/mix) is the root of the narrative's wordplay with Bāḇel: the city's name encodes its theological verdict. The Babylonian name for Babylon — <em>Bāb-il</em> (gate of god) — claimed it was the site of divine-human connection; Genesis retitles it "Confusion" (<em>bālal</em>), rejecting the self-designation and offering a counter-interpretation. For the Israelite audience who knew Babylon as the great imperial power that destroyed Jerusalem, this alternative etymology was a profound theological statement about the true identity of the empire.</p>""",
    "8": """<p>"The LORD scattered them from there over all the earth" — the exact outcome the builders tried to prevent (v4: "otherwise we will be scattered") is enacted by YHWH. The human project that was designed to prevent scattering caused scattering. The Hebrew verb <em>pûṣ/pāṣāh</em> (to scatter) is the same verb used in Gen 9:19 for the post-flood dispersal from Noah's sons. The scattering at Babel is the mechanism that produces the diversity of peoples catalogued in ch10 — though as noted in v5 above, ch10's literary placement before ch11 means the reader sees the result before the cause. The city that was meant to be the center of human unity becomes the site of human dispersal.</p>""",
    "9": """<p>"That is why it was called Babel (<em>Bāḇel</em>) — because there the LORD confused (<em>bālal</em>) the language of the whole world" — the narrative's climactic wordplay. The great city of Babylon, which stands in the ancient world as the symbol of cultural achievement, imperial power, and religious ambition, is renamed by the Genesis narrative as a site of divine judgment. <em>Bāḇel / bālal</em> (Babel / confuse) — the assonance reinterprets Babylon's grandeur as divine judgment on human hubris. For Israel exiled in Babylon (the probable final context of this text's reception), the naming is a theological survival strategy: the empire that crushed you was itself judged at its origin point. The Babel narrative ends where the genealogy of ch10 began — with the dispersal of "the nations over the face of the whole earth," now explained causally.</p>""",
    "10": """<p>The second genealogy of Shem (cf. ch10:22-31) now narrows to the single covenant-line that leads to Abram. "Two years after the flood, when Shem was 100 years old, he became the father of Arphaxad" — the precise chronological anchor (two years after the flood) creates continuity with the flood narrative and establishes the genealogy as a datable timeline. The dramatic shortening of lifespans from the antediluvian genealogy (ch5: patriarchs living 895-969 years) to the post-flood genealogy (ch11: Shem 600 years, decreasing to Nahor's 148 years) is a consistent pattern. The Sumerian King List shows the same dramatic reduction in post-flood kings' reigns compared to pre-flood kings.</p>""",
    "11": """<p>Shem's secondary lifespan of 500 years after Arphaxad (total: 600 years) begins the post-flood genealogy's decreasing pattern. Unlike ch5's genealogy, which explicitly records the death of each patriarch with the formula "and he died," ch11's genealogy omits the death-refrain for most entries (only Terah's death is noted explicitly in v32). The omission shifts the narrative focus from the meditation on mortality (ch5's theological point) to the rapid narrowing toward Abram. The genealogy is not pausing to contemplate death; it is rushing to covenant.</p>""",
    "12": """<p>Arphaxad's 35-year lifespan before Shelah's birth continues the progressively decreasing first-birth ages of the post-flood genealogy (Shem: 100; Arphaxad: 35; Shelah: 30; Eber: 34; Peleg: 30; Reu: 32; Serug: 30; Nahor: 29; Terah: 70). The dramatically shorter post-flood ages compared to the antediluvian genealogy (where first-birth ages ranged from 65 to 187) reflects the general trend of declining lifespans as the narrative approaches the patriarchal period. Whether this represents a literal biological change, a different counting system, or symbolic compression is not resolved by the text itself.</p>""",
    "13": """<p>Arphaxad's secondary lifespan of 403 years gives him a total of 438 years — significantly shorter than the antediluvian patriarchs but still dramatically longer than any modern human lifespan. The genealogy's detail ("had other sons and daughters") consistently reminds the reader that the covenant-line is one thread within a much larger family — the named heir is the covenant-bearer, not the only survivor. The pattern of secondary children maintained in every generation ensures the covenant-line is not presented as the entire population but as the specific line of selection within a broader family.</p>""",
    "14": """<p>Shelah's 30-year lifespan before Eber's birth places the Eber generation approximately 65-70 years after the flood (Shem: 100 at Arphaxad's birth + 2 post-flood = 102 post-flood; Arphaxad: 35 years later = 137 post-flood; Shelah: 30 years later = 167 post-flood; Eber: 34 years later = 201 post-flood). The genealogy's compressed timeline from Noah to Abram means that multiple generations of patriarchs were alive simultaneously — Noah himself, according to the genealogy's internal chronology, was still alive when Abram was born, though they apparently did not interact in the narrative.</p>""",
    "15": """<p>Shelah's secondary lifespan of 403 years (total: 433 years) mirrors Arphaxad's exactly — a rare case of identical secondary-lifespan figures in the genealogy. Eber's birth from Shelah is the next step toward the "sons of Eber" (Hebrews) who are named as Shem's defining legacy in 10:21. The genealogy is building toward its own interpretive key: Shem's significance is that he is the ancestor of the Hebrews, and the chain from Shem to Eber is the genealogical argument for that claim.</p>""",
    "16": """<p>Eber's 34-year lifespan before Peleg's birth, combined with Peleg's name-explanation in 10:25 ("in his time the earth was divided"), places the Babel dispersion approximately 101 years after the flood in the genealogy's internal chronology. Eber himself lives 464 years (the longest lifespan in the post-flood genealogy, even longer than Shem) — a detail that may be narratively significant, as the ancestor of the Hebrews outlives many of the post-flood patriarchs. Eber's long life means he was alive through the entire patriarchal period up to and including the time of Abraham's grandson Jacob.</p>""",
    "17": """<p>Eber's secondary lifespan of 430 years gives him the longest total lifespan in the post-flood genealogy (464 years) — longer even than Shem (600 years total, but Shem is the father of the line rather than the eponymous ancestor of the covenant people). The figure 430 years is the same as Israel's sojourn in Egypt (Exod 12:40-41) — a numerical coincidence that later interpreters have noted, though the text makes no explicit connection. The overall pattern of Eber's exceptional longevity within the decreasing-lifespan post-flood genealogy may mark him as the pivot point: the "sons of Eber" will carry the covenant identity that outlasts all the other post-flood genealogical lines.</p>""",
    "18": """<p>Peleg's 30-year lifespan before Reu's birth continues the short first-birth ages of the post-flood genealogy. Peleg's generation marks the post-Babel world: in Peleg's time the earth was divided (10:25), and now the genealogy moves through the divided, multi-lingual world toward the one man YHWH will call to be the covenant mediator. The genealogy does not comment on the Babel event again — it simply narrates the chain of generations in its wake, moving steadily toward Abram.</p>""",
    "19": """<p>Peleg's total lifespan of 239 years marks the dramatic drop from the immediately preceding generations (Eber: 464 years; Shelah: 433 years; Arphaxad: 438 years) to a significantly shorter life. The genealogy's decreasing lifespans accelerate in Peleg's generation and continue through Reu (239), Serug (230), Nahor (148), and Terah (205). Whether the short lifespan of Peleg reflects the judgment of the Babel dispersion (the divided earth of his time) or simply continues the overall trend is not explained. The trend is consistent: post-Babel lifespans decrease toward the patriarchal range (Abraham: 175 years; Isaac: 180 years; Jacob: 147 years).</p>""",
    "20": """<p>Reu's 32-year lifespan before Serug's birth and his 207-year secondary lifespan (total: 239 years) show the genealogy approaching the patriarchal period's lifespan range. The name Reu (<em>Rĕʿû</em>) may mean "friend/companion" — possibly connected with the Akkadian theophoric element <em>Rê'u</em> (shepherd). Whether the names in the post-Babel genealogy were chosen for their meanings or simply preserved from tradition is unknown. The genealogy has transitioned from the world-historical scope of the Table of Nations (ch10) to the intimate focus of one family's chain of succession toward the patriarch of the covenant.</p>""",
    "21": """<p>Reu's secondary lifespan of 207 years after Serug's birth completes his 239-year total. The genealogy from Shem to Abram covers ten generations — the same number as Adam to Noah in ch5. The parallel structure (ten antediluvian, ten post-flood/post-Babel generations) creates a symmetry that frames both genealogies as complete epochs: the pre-flood world and the pre-Abraham world each have their ten-generation span before a new covenant-stage begins. The ten-generation structure may be conventional (the Sumerian King List has a similar pre-flood/post-flood structure) or may reflect a deliberate literary-theological architecture.</p>""",
    "22": """<p>Serug's 30-year lifespan before Nahor's birth and his 200-year secondary lifespan (total: 230 years) continue the declining trend. The name Serug (<em>Sĕrûg</em>) is attested as a place name in the region of Haran (Sarugi in Assyrian texts) — consistent with the family's eventual settlement in Haran (v31). This geographical connection suggests that the names in the genealogy may preserve authentic geographical-ethnographic memory of the family's origins in the north Syrian/upper Mesopotamian region.</p>""",
    "23": """<p>Serug's secondary lifespan of 200 years completes his 230-year total. The genealogy is approaching Terah's generation — the father of Abram. The entire genealogy from Shem (v10) to Terah (v26) covers approximately 290 years in the internal chronology (adding the first-birth ages: 100+35+30+34+30+32+30+29+70 = 390 years from Shem to Abram's birth; Abram was born when Terah was 70). This means Noah (who lived 350 years after the flood, 9:28) died approximately 60 years before Abram's birth — a calculable overlap that the rabbis and church fathers noted in their chronological studies.</p>""",
    "24": """<p>Nahor's 29-year lifespan before Terah's birth is the shortest first-birth age in the genealogy — by 29, Nahor has his key heir. His total lifespan (148 years) is dramatically shorter than the earlier post-flood patriarchs — the briefest in the Shemite line. The accelerating compression of lifespans as the genealogy approaches Abram's generation reflects the transition from the antediluvian and immediate post-flood world to the fully historical patriarchal period. Abram's own lifespan (175 years, 25:7) will be remarkable for his age but not extraordinary by the genealogy's own standards.</p>""",
    "25": """<p>Nahor's secondary lifespan of 119 years (total: 148 years) confirms the dramatic life-shortening: from Eber's 464 years to Nahor's 148 in four generations. The name Nahor appears twice in the Genesis genealogies — both as Abram's grandfather (here) and as Abram's brother (v26,29). This repetition may reflect family naming patterns (naming a child after a grandparent) or preserve two distinct individuals whose names were the same. The brother Nahor's wife Milcah (v29) will be the grandmother of Rebekah (22:23; 24:15) — another genealogical connection tying the Abrahamic and Nahorite family lines together for the marriage arrangements that follow.</p>""",
    "26": """<p>"After Terah had lived 70 years, he became the father of Abram, Nahor and Haran" — the three-son structure of Terah mirrors Noah's three sons (Shem, Ham, Japheth) and anticipates the narrative's narrowing to the covenant-line within the family. Abram is named first (covenant priority, as Shem was named first among Noah's sons) though there are indications he may not be the firstborn — the chronological calculations suggest Haran was older. The listing of Abram first signals his covenant-narrative significance rather than birth order. Terah's 70-year first-birth age is by far the longest in the post-flood genealogy (the next longest is Shem's 100 years), suggesting Terah's family began late in a period of compressed lifespans.</p>""",
    "27": """<p>The <em>tôlĕḏôt</em> formula — "This is the account of Terah's family line" — marks a new narrative unit: the story of Abram begins here, even before his call in ch12. The introduction of Lot (son of Haran) is significant: Lot's status as an orphan under Abram's household care explains his presence throughout the Abraham narrative (12:4; 13:1,5-12; 14:12-16; 18:1-19:29). In the ANE, a nephew whose father had died was absorbed into the paternal uncle's household — Abram is Lot's effective guardian. The extended family unit that will travel together (Abram, Sarai, Lot) is assembled here.</p>""",
    "28": """<p>"Haran died in Ur of the Chaldeans, in the land of his birth" — Ur (<em>Ûr Kaśdîm</em>, Ur of the Chaldeans) is one of the oldest and greatest cities of the ancient world. Archaeological excavations of Ur (beginning with Woolley's work in the 1920s-30s) revealed a sophisticated urban civilization with elaborate royal burials (the Royal Cemetery of Ur, ca. 2600-2500 BCE), advanced architecture, and literacy. "Of the Chaldeans" is either an anachronism (the Chaldeans became prominent in Babylonia only ca. 900 BCE) or reflects the ANE practice of identifying ancient places by later, better-known inhabitants for the reader's orientation. Haran's death in Ur "in the land of his birth" is a poignant detail: the family's departure from Ur will not be fully accomplished — Haran remains there forever.</p>""",
    "29": """<p>Abram's marriage to Sarai and Nahor's marriage to Milcah (daughter of Haran) establish the family's endogamous marriage practice — marrying within the clan, here specifically niece-marriage (Nahor married his niece Milcah). Endogamy was the ANE norm for maintaining family property and covenant identity: Rebekah (Abraham's daughter-in-law, Gen 24) will be found among Nahor's descendants precisely because the covenant family must marry within its kinship network. The detail that Milcah is "the daughter of Haran, the father of both Milcah and Iscah" establishes the genealogical precision needed for the later marriage arrangements of Isaac (who will marry Rebekah, Milcah's granddaughter, 22:23; 24:15).</p>""",
    "30": """<p>"Sarai was childless (<em>ʿăqārāh</em>) because she was not able to conceive" — the word <em>ʿăqārāh</em> (barren/childless) introduces the defining crisis of the Abraham narrative: the one to whom YHWH will promise "a great nation" has a barren wife. Barrenness in the ANE was socially devastating: a woman's honor and social standing were closely tied to her fertility; childlessness was experienced as divine disfavor or curse. The same barrenness pattern recurs for Rebekah (25:21) and Rachel (29:31), establishing it as the recurring crisis through which YHWH demonstrates his covenant power. In each case, the barrenness of the covenant-mother is the occasion for divine intervention — the miraculous birth of the covenant-son.</p>""",
    "31": """<p>"Terah took his son Abram, his grandson Lot son of Haran, and his daughter-in-law Sarai... and together they set out from Ur of the Chaldeans to go to Canaan. But when they came to Haran, they settled there" — the journey from Ur to Canaan follows the Fertile Crescent: up the Euphrates valley to Haran (in the region of modern Turkey/Syria border), then southwest into Canaan. Haran was a major trading and religious center — home to the worship of Sin, the moon-god (the same deity worshipped in Ur). Josh 24:2 records that Abram's ancestors "served other gods beyond the River" — the family's departure from Ur is not yet a full covenant break from ANE religion. Terah stops at Haran, the city that bears his dead son's name, and does not complete the journey. The incomplete first journey becomes complete when YHWH calls Abram in ch12.</p>""",
    "32": """<p>"Terah lived 205 years, and he died in Haran" — Terah's death in Haran closes the genealogical narrative and opens the covenant narrative. The genealogy that began with Shem (v10) has reached its destination: the family of Terah, living in Haran, with Abram among them, waiting for the divine call that will resume the aborted journey to Canaan. The death of the father is the narrative precondition for the son's departure: Abram can now be called to leave "your father's household" (12:1) because the father's household has been dissolved by death. Gen 12:1's call comes after Terah's death — the covenant journey begins where the family journey ended.</p>"""
  },
  "12": {
    "2": """<p>"I will make you into a great nation, and I will bless you; I will make your name (<em>šĕmekā</em>) great, and you will be a blessing" — the covenant promise contains three elements: national identity, blessing, and name-greatness. The name-greatness promise directly reverses the Babel program (11:4: "let us make a name/<em>šēm</em> for ourselves"): at Babel, self-manufactured name results in scattering; in the covenant, YHWH-given name results in blessing. The covenant's name-gift is the anti-Babel. The seven-fold structure of the covenant promises in vv2-3 (I will, I will, I will, you will be, I will, whoever curses you I will, all peoples will be blessed) may be deliberate — seven as the number of completeness.</p>""",
    "3": """<p>"All peoples on earth (<em>kol mišpĕḥōt hāʾădāmāh</em>) will be blessed through you" — the universal scope of the Abrahamic covenant is established from its first statement. The "families of the ground" are the 70 peoples of ch10 — every nation listed in the Table of Nations is the beneficiary of the covenant that begins here. Paul cites this verse in Galatians 3:8 as "the gospel announced in advance to Abraham" (<em>proeuēngelisato</em>) — the first gospel proclamation was not to Israel but to Abraham about the nations. The covenant with one particular man is simultaneously the covenant for all peoples. The narrowing of the covenant-line from Noah to Shem to Eber to Terah to Abram in chs 9-11 is now revealed as purposeful narrowing toward a universal goal.</p>""",
    "4": """<p>"Abram went, as the LORD had told him" — the obedience formula echoes Noah's comprehensive obedience (6:22; 7:5) and places Abram in the line of covenant-faithful servants. Abram's departure at 75 years of age is significant in ANE terms: at 75, a man of Abram's social standing would typically be settled, with established household arrangements, land, and inheritance plans. To "leave your country, your people and your father's household" (12:1) at 75 is to abandon everything that constituted ANE social identity and security. The Hittite treaty texts specify that vassal-kings who obeyed the great king's summons received the great king's protection; Abram's obedience to YHWH's summons follows this suzerain-vassal treaty pattern.</p>""",
    "5": """<p>"The people they had acquired (<em>hanepeš ʾăšer-ʿāśû</em>) in Haran" — the Hebrew <em>nepeš</em> (usually translated "soul/person/being") here means servants or household members attached to Abram's household through purchase, debt-bondage, or voluntary attachment. A wealthy patriarch's household in the ANE was a social unit encompassing extended family, servants, clients, and dependents. Abraham's later ability to mobilize 318 trained men from his household (14:14) confirms the scale of this community — an entire small village traveling with him. "People acquired in Haran" may also reflect Abram's religious influence during his time there — those who joined his covenant community as proselytes or clients.</p>""",
    "6": """<p>"The great tree of Moreh (<em>ʾēlôn môreh</em>) at Shechem" — sacred trees were sites of divine communication and worship in Canaanite religion: the term <em>ʾēlôn</em> (terebinth/oak/great tree) is associated with oracle-giving (<em>môreh</em> = teacher/oracle-giver). The patriarchs consistently establish covenant-worship sites at or near existing Canaanite sacred sites, effectively claiming the sacred geography for YHWH. Shechem itself is the first city in Canaan that Abram visits — and it will become a central covenant-renewal site throughout Israel's history (Josh 24:1-28; Judg 9; 1 Kgs 12:1). "At that time the Canaanites were in the land" — the narrator's matter-of-fact comment acknowledges the obvious: the land YHWH promises to Abram is currently occupied by other peoples. The promise is prospective, requiring centuries of divine action to fulfill.</p>""",
    "7": """<p>"The LORD appeared (<em>wayyērāʾ</em>) to Abram" — the niphal of <em>rāʾāh</em> (to see/appear) is the standard theophany verb throughout the patriarchal narratives (17:1; 18:1; 26:2,24; 35:1,9). YHWH's appearances to the patriarchs are consistently unannounced and location-specific — the theophany occurs at a particular place, and the patriarch's response is to consecrate that place with an altar. "To your offspring (<em>lĕzarʿăkā</em>) I will give this land" — the first land-promise is immediately addressed to Abram's offspring rather than to Abram himself: the promise is for the future, not the present. Abram builds an altar in response to the promise he will not personally receive — an act of faith in YHWH's future faithfulness.</p>""",
    "8": """<p>"There he built an altar to the LORD and called on the name of the LORD" — the altar between Bethel and Ai is the second of Abram's covenant-worship sites (Shechem was first; Hebron at 13:18 and Beersheba at 21:33 will follow). The phrase "calling on the name of the LORD" (<em>wayyiqrāʾ bĕšēm YHWH</em>) is the standard formula for covenantal prayer and worship established in Gen 4:26 (the beginning of formal YHWH-worship in Seth's line). Bethel (house of God) becomes the most significant patriarchal worship site: Jacob will have his ladder-vision here (28:18-22) and later return to consecrate it (35:1-15). The patriarchal altar-network (Shechem, Bethel, Hebron, Beersheba) maps the covenant-claim on the land by marking its major sites with YHWH-worship before Israel formally inherits them.</p>""",
    "9": """<p>"Abram continued toward the Negev" — the Negev (<em>negev</em>, literally "dry/south") is the semi-arid steppe region south of the Judean hill country, transitional between Canaan and the Sinai. In the patriarchal period, the Negev was used as seasonal pastureland by semi-nomadic peoples. Abram's movement southward follows the pastureland available for his flocks. The Negev will be a recurring location in Abram's movements (13:1; 20:1; 21:14) and in later Israelite history (Num 13:17; the Amalekites lived in the Negev, 1 Sam 27:10). The southward drift sets up the Egypt episode: from the Negev, Egypt is the next natural destination when famine strikes.</p>""",
    "10": """<p>"There was a famine in the land, and Abram went down (<em>wayyēreḏ</em>) to Egypt" — famines caused by insufficient seasonal rainfall were a recurring feature of Canaanite life, driving population toward Egypt whose Nile-inundation agriculture was drought-resistant. Egyptian texts record the arrival of Canaanite and Semitic groups during times of famine (the "Beni Hasan" tomb painting from ca. 1900 BCE depicts a group of Semitic traders/refugees entering Egypt with donkeys, strikingly close to the biblical period). The verb "went down" (<em>yārad</em>) is the standard term for entering Egypt from Canaan — Egypt is geographically lower, and the term will be used for Jacob's family in Gen 42-46. The pattern: famine in Canaan → descent to Egypt → divine protection → exit with wealth → prefigures the national Exodus narrative.</p>""",
    "11": """<p>"I know what a beautiful woman you are" — Abram's assessment of Sarai's beauty is the preamble to his calculation of the Egyptian danger. In the ANE, a beautiful woman traveling without recognized social protection was at risk of being seized; her husband's death would remove the marriage-claim, leaving the widow legally vulnerable. Abram's fear is not irrational in the ANE context: Egyptian texts and wisdom literature warn of the social violence that beautiful women could attract from powerful men. The personal address ("I know") suggests a tender context for what is, in effect, a dangerous proposal.</p>""",
    "12": """<p>"When the Egyptians see you, they will say, 'This is his wife.' Then they will kill me but will let you live" — Abram's risk calculation reflects ANE social reality. A man who wanted another man's wife faced the obstacle of the husband's legal claim; killing the husband was one way to remove that obstacle. The same dynamic appears in David's arrangement for Uriah's death (2 Sam 11). Abram's fear is that his identity as Sarai's husband makes him a target. The plan that follows will protect Abram's life by placing Sarai's status in jeopardy — a morally compromised calculation that the narrative does not endorse.</p>""",
    "13": """<p>"Say you are my sister (<em>ʾăḥōtî</em>)" — Abram's request is based on a half-truth: 20:12 reveals that Sarai is indeed Abram's half-sister (same father, different mothers). In the ANE, a "sister-wife" relationship was legally recognized in certain contexts (known from Hurrian legal texts found at Nuzi, ca. 1500 BCE, where a woman could be simultaneously a man's wife and adoptive sister for legal protection purposes). Whether Abram is exploiting this legal ambiguity or simply using a partial truth as deception, the effect is to make Sarai available for negotiation as a potential wife — placing her in danger while protecting him. The twice-repeated pattern (here and ch20 with Abimelech; Isaac replicates it in 26:7-11) is a recurring patriarchal failure that the narrative documents without excusing.</p>""",
    "14": """<p>"When Abram came to Egypt, the Egyptians saw that Sarai was a very beautiful woman" — the fulfillment of Abram's prediction in v12. Egypt's bureaucratic attention to arriving immigrants and the Egyptian aesthetic appreciation of female beauty are both attested in Egyptian literature (the Tale of Two Brothers; the Instruction of Any both note the dangers of beautiful women for men in Egypt). The escalation from "the Egyptians saw" to "Pharaoh's officials saw and praised her to Pharaoh" (v15) reflects the court-patronage system: beauty that attracted lower officials' attention was escalated to the higher patron's (Pharaoh's) potential interest.</p>""",
    "15": """<p>"When Pharaoh's officials saw her, they praised her to Pharaoh, and she was taken into his palace" — the court-patronage chain operates efficiently: beauty reported upward through the hierarchy reaches Pharaoh, who exercises royal prerogative. Pharaoh's household (<em>bêt parʿōh</em>) is the harem, the collection of women under royal protection/ownership. Egyptian pharaohs maintained extensive harems (Ramesses II famously had over 200 children from numerous wives and concubines); the royal harem was a recognized institution with its own administrative structure. Sarai's entry into Pharaoh's household is not presented as voluntary; it is the exercise of royal power over a woman without effective social protection.</p>""",
    "16": """<p>"He treated Abram well for her sake" — the gift-exchange: Abram receives sheep, cattle, donkeys, servants, and camels as compensation for Sarai as a potential wife, functioning as her "brother/guardian." This is the standard ANE bride-price negotiation — the woman's male guardian received gifts in exchange for the marriage arrangement. Abram's wealth is thus increased through his wife's endangered status, a dark irony the narrative notes without comment. The specific mention of camels is historically interesting: the domesticated camel's prevalence in the patriarchal period has been debated by archaeologists (camels were used but not as commonly as Genesis implies, according to some scholars), though camel domestication is attested in the early second millennium BCE in Arabia.</p>""",
    "17": """<p>"The LORD inflicted serious diseases (<em>nĕgāʿîm gĕḏōlîm</em>) on Pharaoh and his household because of Abram's wife Sarai" — YHWH's protection of Sarai activates the covenant promise of v3 ("whoever curses you I will curse"). Pharaoh's household suffers divine plagues (<em>nĕgāʿîm</em>) — the same word used for the plagues of the Exodus narrative (Exod 11:1; 12:13). The verbal echo is almost certainly intentional: what YHWH does to one Pharaoh's household because of one Israelite woman prefigures what YHWH will do to all of Pharaoh's Egypt because of the entire Israelite people. The pattern of individual → national is a key typological structure in Genesis: Abram's experience in Egypt is the seed of the Exodus story.</p>""",
    "18": """<p>"What have you done to me? Why didn't you tell me she was your wife?" — Pharaoh's confrontation with Abram is the third instance in Genesis of a powerful pagan ruler rebuking a patriarch for deception (cf. 20:9-10: Abimelech confronting Abraham; 26:9-10: Abimelech confronting Isaac). In each case, the pagan ruler demonstrates clear moral perception of the deception, creating an irony that does not excuse the patriarch. The narrative's honest portrayal of the patriarchs' failures — including the founding patriarch Abram — is part of its theological realism: the covenant does not depend on the patriarchs' moral perfection but on YHWH's faithfulness to his promises despite human failure.</p>""",
    "19": """<p>"Why did you say, 'She is my sister,' so that I took her to be my wife?" — Pharaoh's question reveals his understanding: he took Sarai in good faith as an available woman, not knowing she was married. His rebuke of Abram is justified: "Here is your wife. Take her and go!" The verb translated "take her and go" (<em>qah wālēk</em>) is abrupt and dismissive — Pharaoh is expelling Abram without ceremony. The expulsion is the conclusion of an episode in which Abram has both protected his own life through deception and received considerable wealth — while Sarai bore the danger and Pharaoh bore the plagues. The moral accounting of the episode is left for the reader to assess.</p>""",
    "20": """<p>"Pharaoh gave orders about Abram to his men, and they sent him on his way, with his wife and everything he had" — the expulsion from Egypt with wealth intact is the final element in the pattern-parallel to the Exodus. The corresponding Exodus text (Exod 12:35-36) records Israel "leaving Egypt with the Egyptians' silver and gold." The parallel between Abram's Egypt episode and the national Exodus is systematically complete: famine drives descent to Egypt (cf. Gen 47; Exod 1); YHWH inflicts plagues on Pharaoh's household (cf. the ten plagues of Exod 7-12); Pharaoh summons and confronts the covenant-party (cf. Exod 12:31-32); the covenant-party departs with wealth (cf. Exod 12:35-36). What happens to Abram individually in ch12 happens to his descendants nationally in Exodus — Genesis narratively prefigures Israel's founding story.</p>"""
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_CONTEXT)
    save_comm('mkt-context', 'genesis', existing)

    result = load_comm('mkt-context', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [10, 11, 12]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f'  Genesis context total: {total_chs} chapters, {total_vv} verses')
    print('Genesis 10–12 mkt-context written.')

if __name__ == '__main__':
    main()
